"""
MKT Original Language Commentary — Galatians chapters 4–6
Run: python3 scripts/zc-original-galatians-4-6.py

Source data used:
- data/interlinear/galatians.json
- data/translation/glossary-greek.json (sarx G4561 disp=4, pneuma G4151 disp=3,
  pistis G4102 disp=3)
- data/translation/draft/mediating/galatians.json (MKT text for quotation)
- data/commentary/mkt-original/galatians.json (read ch.1-3 before writing)

Key decisions in this range:
- 4:4 "born of a woman" (genomenos ek gynaikos) — the aorist participle marks the
  contingent entry into human existence; the phrase is Paul's minimal Incarnation
  claim. "Born under the law" (genomenos hypo nomon) adds the covenant-location.
- 4:6 "the Spirit of his Son" (pneuma tou huiou autou) — an unusual designation;
  the Spirit is here identified with Christ's own filial relation to the Father,
  grounding the believer's Abba-cry in Christ's own filial identity.
- 4:24 "allegorically" (allēgoroumena) — Paul's allegory is typological reading,
  not the replacement of the historical narrative; Hagar and Sarah remain real
  people, but their situations carry additional covenantal significance that
  Paul draws out.
- 5:1 "freedom with which Christ freed us" — ēleutherōsen aorist, definitive past
  act. The dative tē eleutheria is debated: either "for freedom" (purpose) or
  "in freedom" (sphere); the purpose reading is more natural.
- 5:5 elpida dikaiosynes — "hope of righteousness" — the righteousness here is
  probably the final eschatological verdict, not present justification; Paul is
  describing the believer's forward orientation.
- 6:2 "law of Christ" (nomos tou Christou) — the only occurrence of this phrase
  in Paul; it probably refers not to a new legal code but to the principle/pattern
  of Christ's own self-giving love (cf. John 13:34), described as "law" because
  it governs conduct.
- Continuity from ch.1-3: same handling of pistis Christou (objective genitive),
  sarx (both neutral human nature and fallen flesh-principle, context-dependent),
  nomos without article = law-principle.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GALATIANS = {
  "4": {
    "1": '<p><strong>ὁ κληρονόμος νήπιός ἐστιν</strong> (the heir is a minor/underage child, G3516) — <em>nēpios</em> denotes the child not yet of legal age, who possesses the inheritance legally but cannot access it independently. The analogy maps onto the OT period: Israel was heir to the promise but under guardianship, not yet in full possession.</p>',
    "2": '<p><strong>ὑπὸ ἐπιτρόπους ἐστὶν καὶ οἰκονόμους</strong> (under guardians and trustees) — two classes of people managing the minor\'s affairs: <em>epitropoi</em> (guardians of the person) and <em>oikonomoi</em> (trustees of the estate). The law performed both functions: guarding conduct and managing the promise-inheritance before the fullness of time.</p>',
    "3": '<p><strong>ὑπὸ τὰ στοιχεῖα τοῦ κόσμου</strong> (under the elemental spirits/principles of the world, G4747) — <em>stoicheia</em> is debated: elemental principles of learning (ABCs), elemental heavenly bodies, or elemental spiritual powers. The context (enslaved condition requiring divine redemption) suggests more than mere religious categories; the same term appears at v.9 for the powers the Galatians would return to.</p>',
    "4": '<p><strong>ὅτε δὲ ἦλθεν τὸ πλήρωμα τοῦ χρόνου</strong> (but when the fullness of time came, G4138) — <em>plērōma tou chronou</em>: not merely calendar timing but the completion/filling-up of the appointed period. History was moving toward this moment. <strong>ἐξαπέστειλεν ὁ θεὸς τὸν υἱὸν αὐτοῦ</strong> (God sent out his Son, G1821) — the compound <em>exapostellō</em> implies sending out from the divine sphere, presupposing the Son\'s pre-existence. <strong>γενόμενον ἐκ γυναικός, γενόμενον ὑπὸ νόμον</strong> (born of a woman, born under the law) — the two aorist participles mark the double contingency of the Incarnation: entering human nature and entering the specific covenant domain of the law.</p>',
    "5": '<p><strong>ἵνα τοὺς ὑπὸ νόμον ἐξαγοράσῃ</strong> (to redeem those under the law, G1805) — the aorist subjunctive of purpose; <em>exagorazō</em> (to buy out of the marketplace) indicates payment and liberation from a condition of bondage. <strong>ἵνα τὴν υἱοθεσίαν ἀπολάβωμεν</strong> (that we might receive adoption to sonship, G5206) — <em>apolabōmen</em> (receive back/in full) suggests receiving what was always promised but not yet possessed. <em>Huiothesia</em> is the formal legal adoption-term, as in Rom 8:15,23.</p>',
    "6": '<p><strong>ἐξαπέστειλεν ὁ θεὸς τὸ πνεῦμα τοῦ υἱοῦ αὐτοῦ</strong> (God sent out the Spirit of his Son) — the compound <em>exapostellō</em> is the same verb as v.4 for sending the Son; the Spirit\'s sending parallels the Son\'s sending. <strong>τοῦ υἱοῦ αὐτοῦ</strong> (of his Son) — the Spirit is identified as the Son\'s own Spirit, grounding the believer\'s filial cry in the Son\'s own relationship with the Father. <strong>κρᾶζον Ἀββά, ὁ πατήρ</strong> (crying Abba, Father, G2896) — the present participle describes ongoing crying; the Spirit\'s cry is continuous, not a one-time event.</p>',
    "7": '<p><strong>ὥστε οὐκέτι εἶ δοῦλος ἀλλὰ υἱός</strong> (so that you are no longer a slave but a son) — the transition from slave-status to son-status is the direct consequence of the double sending (Son and Spirit) of vv.4-6. The address shifts to second singular: this is personal and specific, not merely corporate. <strong>κληρονόμος διὰ θεοῦ</strong> (heir through God) — the inheritance is now accessible through divine action rather than held in suspension under guardianship.</p>',
    "8": '<p><strong>τοῖς φύσει μὴ οὖσιν θεοῖς ἐδουλεύσατε</strong> (you were slaves to those who by nature are not gods) — <em>physis</em> (G5449) marks the ontological claim: the pagan deities have no real divine nature. The enslavement was real but directed at non-entities; the more striking slavery would be returning to bondage of any kind after being freed (v.9).</p>',
    "9": '<p><strong>νῦν δὲ γνόντες θεόν, μᾶλλον δὲ γνωσθέντες ὑπὸ θεοῦ</strong> (but now knowing God, or rather being known by God) — the correction (<em>mallon de</em> = but rather) is theologically significant: Paul prefers the passive construction to the active, since divine initiative precedes and grounds human knowing. The knowing is relational, not merely cognitive. <strong>πῶς ἐπιστρέφετε πάλιν</strong> (how are you turning back again?) — the present tense captures the in-process reversal; there is still time.</p>',
    "10": '<p><strong>ἡμέρας παρατηρεῖσθε καὶ μῆνας καὶ καιροὺς καὶ ἐνιαυτούς</strong> (you observe days and months and seasons and years, G3906) — the calendar observances are symptoms rather than the disease; the disease is re-submission to law as a means of standing before God. The list moves from smallest to largest temporal unit, suggesting comprehensive calendar-compliance.</p>',
    "11": '<p><strong>φοβοῦμαι ὑμᾶς</strong> (I fear for you) — the first person present expression of pastoral anxiety; Paul\'s fear is not about them as persons but about the possible futility of his previous labor among them. <strong>μή πως εἰκῇ κεκοπίακα εἰς ὑμᾶς</strong> (lest somehow I have labored in vain among you) — the perfect <em>kekopika</em> (I have labored) marks the sustained investment; the adverb <em>eikē</em> (in vain, without result) is the feared outcome.</p>',
    "12": '<p><strong>γίνεσθε ὡς ἐγώ, ὅτι κἀγὼ ὡς ὑμεῖς</strong> (become like me, because I also became like you) — the reciprocal becoming: Paul became like Gentiles (freed from the law\'s jurisdiction) in his apostolic practice (cf. 1 Cor 9:21); now he calls them to become like him (standing in the freedom of Christ). The ethical argument is autobiographical before it is propositional.</p>',
    "13": '<p><strong>δι᾽ ἀσθένειαν τῆς σαρκός</strong> (because of weakness of the flesh, G4561 disp=4) — here <em>sarx</em> is neutral: physical flesh, bodily weakness. The illness is not named but was Paul\'s occasion for first preaching in Galatia; the providential use of personal weakness is an implicit argument against flesh-reliance.</p>',
    "14": '<p><strong>τὸν πειρασμὸν ὑμῶν ἐν τῇ σαρκί μου</strong> (your trial in my flesh) — Paul acknowledges that his bodily condition was itself a test for the Galatians: would they reject someone physically afflicted? <strong>ὡς ἄγγελον θεοῦ ἐδέξασθέ με, ὡς Χριστὸν Ἰησοῦν</strong> (you received me as an angel of God, as Christ Jesus) — the reception was apostolic: through Paul\'s preaching they encountered Christ himself (cf. 4:19).</p>',
    "15": '<p><strong>ὁ μακαρισμὸς ὑμῶν</strong> (your blessing/congratulation of me) — the term <em>makarismos</em> (G3108) refers to the previous beatitude/blessing the Galatians pronounced over Paul; the question "where is it now?" implies its disappearance. The hypothetical self-sacrifice ("you would have plucked out your eyes") suggests a particularly deep affection and commitment that has since cooled.</p>',
    "16": '<p><strong>ἐχθρὸς ὑμῶν γέγονα ἀληθεύων ὑμῖν</strong> (have I become your enemy by speaking truth to you?) — the perfect <em>gegona</em> (I have become) asks whether a change has occurred in their perception of him; truth-speaking is the thing that produces enmity when the audience doesn\'t want to hear it.</p>',
    "17": '<p><strong>ζηλοῦσιν ὑμᾶς οὐ καλῶς</strong> (they are zealous for you, but not in a good way) — the present tense of the agitators\' ongoing activity; <em>zēloō</em> (G2206) is the verb for zealous pursuit; the "not well" qualifies the motive. <strong>ἐκκλεῖσαι ὑμᾶς θέλουσιν</strong> (they want to shut you out) — <em>ekkleiō</em> (G1576) is to shut out, exclude; the agitators want to cut the Galatians off from Paul\'s gospel-network so they become dependent on the agitators\' alternative.</p>',
    "18": '<p><strong>καλὸν δὲ ζηλοῦσθαι ἐν καλῷ πάντοτε</strong> (it is good to be zealously sought always in what is good) — Paul acknowledges that zeal-toward-someone is not inherently bad; the problem is the purpose and quality of the zeal. The "not only when I am present" (<em>en tō pareinai me</em>) refers to Paul\'s own presence: during his presence the Galatians\' zeal was rightly directed.</p>',
    "19": '<p><strong>τεκνία μου, οὓς πάλιν ὠδίνω</strong> (my little children, for whom I am again in labor pains, G5605) — the birth-pangs metaphor (<em>ōdinō</em> is the verb for labor-pains in childbirth) applied to apostolic travail; Paul is experiencing the same intensity as the initial evangelism. <strong>μέχρις οὗ μορφωθῇ Χριστὸς ἐν ὑμῖν</strong> (until Christ is formed in you, G3445) — the aorist passive subjunctive of <em>morphoō</em>: Christ taking shape/form within the community is the goal of the apostolic labor. The <em>morphē</em> language is the same root as Phil 2:6-7 (<em>morphē theou</em>/<em>morphēn doulou</em>).</p>',
    "20": '<p><strong>ἠθελον δὲ παρεῖναι πρὸς ὑμᾶς ἄρτι</strong> (I wish I could be with you now) — the imperfect <em>ēthelon</em> indicates an unfulfilled desire in the present: he wants to be there but cannot. <strong>ἀπορούμαι ἐν ὑμῖν</strong> (I am at a loss about you, G639) — the present passive: Paul is in a state of perplexity about them, uncertain what to think. The honesty is pastoral rather than rhetorical.</p>',
    "21": '<p><strong>λέγετέ μοι, οἱ ὑπὸ νόμον θέλοντες εἶναι</strong> (tell me, you who want to be under law) — the address is pointed: <em>oî hypo nomon thelontes einai</em> (those desiring to be under the law). The <em>thelontes</em> (wanting, present active participle) implies active desire, not passive entrapment. Paul then asks whether they know what the law says — a rhetorical challenge to attend to what the law itself teaches about being under it.</p>',
    "22": '<p><strong>γέγραπται γὰρ ὅτι Ἀβραὰμ δύο υἱοὺς ἔσχεν</strong> (for it is written that Abraham had two sons) — the perfect <em>gegraptai</em> (it stands written) is the standard citation formula. The two sons structure the entire subsequent allegory: Ishmael from the slave woman (Hagar) by natural means, Isaac from the free woman (Sarah) by promise.</p>',
    "23": '<p><strong>ὁ μὲν ἐκ τῆς παιδίσκης κατὰ σάρκα γεγέννηται</strong> (the one from the slave woman was born according to the flesh, G4561 disp=4) — <em>kata sarka</em> here means by natural biological means, without divine promise-involvement. <strong>ὁ δὲ ἐκ τῆς ἐλευθέρας δι᾽ ἐπαγγελίας</strong> (but the one from the free woman through promise) — the preposition <em>dia</em> specifies the mechanism: the promise was the means by which Isaac came into being.</p>',
    "24": '<p><strong>ἅτινά ἐστιν ἀλληγορούμενα</strong> (which things are being allegorized/taken figuratively, G238) — the present passive participle: Paul is now reading the narrative figuratively, not claiming that the narrative is non-historical. <strong>αὗται γάρ εἰσιν δύο διαθῆκαι</strong> (for these women represent two covenants) — the two women are not merely private individuals but typological representatives of two covenant-administrations: Sinai (Hagar) and the promise (Sarah).</p>',
    "25": '<p><strong>τὸ δὲ Ἅγαρ Σινᾶ ὄρος ἐστὶν ἐν τῇ Ἀραβίᾳ</strong> (now Hagar is Mount Sinai in Arabia) — the identification is geographical and typological: Hagar\'s territory is Arabia, where Sinai is located; the Sinai covenant belongs in the same symbolic geography as Hagar\'s bondage. <strong>συστοιχεῖ δὲ τῇ νῦν Ἱερουσαλήμ</strong> (she corresponds to the present Jerusalem, G4960) — the present Jerusalem (under Rome, under the law\'s continued claim) is in the Hagar-line, not the Sarah-line.</p>',
    "26": '<p><strong>ἡ δὲ ἄνω Ἱερουσαλήμ</strong> (but the Jerusalem above) — the heavenly Jerusalem (cf. Heb 12:22; Rev 21:2) is in the Sarah-line: free. <strong>ἥτις ἐστὶν μήτηρ ἡμῶν</strong> (who is our mother) — the collective identification: believers are children of the free Jerusalem, not the enslaved one. The mother-city metaphor places their identity in the eschatological rather than the earthly Jerusalem.</p>',
    "27": '<p>The citation from Isa 54:1 (LXX) — <strong>εὐφράνθητι, στεῖρα ἡ οὐ τίκτουσα</strong> (rejoice, barren woman who does not bear) — describes the restoration of Zion after exile; Paul applies it to Sarah and to the Jerusalem-above: the woman who seemed barren (Sarah; the new covenant community) will produce more children than the apparently fruitful woman (Hagar; law-covenant Israel). The <em>oti</em> (because) introduces the reason: the barren woman will have more children.</p>',
    "28": '<p><strong>ἡμεῖς δέ, ἀδελφοί, κατὰ Ἰσαὰκ ἐπαγγελίας τέκνα ἐσμέν</strong> (now we, brothers, like Isaac, are children of promise) — the application to the present community: they are in the Isaac-line, children born of promise rather than of natural process. The identification with Isaac and the free woman is the ground of the freedom that follows in ch.5.</p>',
    "29": '<p><strong>ὁ κατὰ σάρκα γεννηθεὶς ἐδίωκεν τὸν κατὰ πνεῦμα</strong> (the one born according to the flesh was persecuting the one according to the Spirit) — Paul identifies the Galatians\' present situation with the Genesis pattern; the natural-birth line persecutes the promise-birth line. The hostility of circumcision-advocates toward Paul\'s uncircumcised-Gentile communities is this pattern repeated.</p>',
    "30": '<p>The Scripture citation (Gen 21:10) — <strong>ἔκβαλε τὴν παιδίσκην καὶ τὸν υἱὸν αὐτῆς</strong> (cast out the slave woman and her son) — is Sarah\'s command to Abraham, recorded in Genesis and treated as scripture\'s own word. <strong>οὐ γὰρ μὴ κληρονομήσῃ ὁ υἱὸς τῆς παιδίσκης μετὰ τοῦ υἱοῦ τῆς ἐλευθέρας</strong> (for the son of the slave woman will not inherit with the son of the free woman) — the double negative (<em>ou... mē</em>) is emphatic: absolute exclusion from shared inheritance.</p>',
    "31": '<p><strong>διό, ἀδελφοί, οὐκ ἐσμὲν παιδίσκης τέκνα ἀλλὰ τῆς ἐλευθέρας</strong> (therefore, brothers, we are not children of the slave woman but of the free woman) — the conclusion drawn from the allegory: the community\'s identity is in the free woman\'s line. The absence of the article before <em>eleutherας</em> gives the characteristic a qualitative force: we are children of the one characterized by freedom, not bondage.</p>'
  },
  "5": {
    "1": '<p><strong>τῇ ἐλευθερίᾳ ἡμᾶς Χριστὸς ἠλευθέρωσεν</strong> (for freedom Christ freed us, G1659) — the dative <em>tē eleutheria</em> is probably a dative of purpose: Christ freed us <em>for</em> freedom. The cognate construction (<em>eleutheria... ēleutherōsen</em>) places freedom at both the beginning and the end: freedom is both the means and the goal. The aorist <em>ēleutherōsen</em> marks a definitive past act. <strong>στήκετε οὖν</strong> (stand firm therefore, G4739) — present imperative: continue standing. <strong>μὴ πάλιν ζυγῷ δουλείας ἐνέχεσθε</strong> (do not be entangled again in a yoke of slavery, G1758) — <em>enechesthe</em> (be entangled, be held in) is present passive imperative: stop being held in.</p>',
    "2": '<p><strong>ἴδε ἐγὼ Παῦλος λέγω ὑμῖν</strong> (behold, I Paul tell you) — the emphatic personal assertion, using the same formula as the oath of 1:20; Paul stakes his personal authority on what follows. <strong>ὅτι ἐὰν περιτέμνησθε, Χριστὸς ὑμᾶς οὐδὲν ὠφελήσει</strong> (that if you are circumcised, Christ will benefit you nothing) — the future <em>ōphelēsei</em> (will benefit) is a statement of theological consequence, not a curse: choosing circumcision as the means of covenant standing removes one from the domain where Christ\'s benefit operates.</p>',
    "3": '<p><strong>πάντι ἀνθρώπῳ περιτεμνομένῳ ὅτι ὀφειλέτης ἐστὶν ὅλον τὸν νόμον ποιῆσαι</strong> (to every person who lets himself be circumcised that he is obligated to do the whole law) — the present passive participle; accepting circumcision as a covenant obligation activates the entire legal system, not a single ritual. The law is not partial: one cannot selectively adopt its benefits without accepting its comprehensive demands.</p>',
    "4": '<p><strong>κατηργήθητε ἀπὸ Χριστοῦ</strong> (you were severed/separated from Christ, G2673) — the aorist passive; the same <em>katargeō</em> verb Paul uses for the law being "nullified" is here used for severance from Christ. The irony: those seeking to add the law to their Christ-faith are severed from Christ. <strong>ἐκ χάριτος ἐξεπέσατε</strong> (you fell from grace, G1601) — the aorist of <em>ekpiptō</em> (to fall out of); grace is a domain and system from which one can exit by shifting to a law-basis.</p>',
    "5": '<p><strong>ἡμεῖς γὰρ πνεύματι ἐκ πίστεως ἐλπίδα δικαιοσύνης ἀπεκδεχόμεθα</strong> (for we, by the Spirit, from/through faith await the hope of righteousness) — the two instruments (<em>pneumati</em> and <em>ek pisteōs</em>) specify how the awaiting happens: by the Spirit and through faith. <em>Elpida dikaiosynēs</em> (hope of righteousness) probably refers to the final eschatological verdict — the full realization of justification at the Last Day — rather than the present imputed status. The present tense <em>apekdechometha</em> (we keep on waiting) is the posture of those who live between the already and the not-yet.</p>',
    "6": '<p><strong>ἐν γὰρ Χριστῷ Ἰησοῦ οὔτε περιτομή τι ἰσχύει οὔτε ἀκροβυστία</strong> (in Christ Jesus neither circumcision nor uncircumcision has any power, G2480) — the sphere <em>en Christō Iēsou</em> is the domain where the ethnic markers cease to be operative; within that domain, the only thing that matters is specified next. <strong>ἀλλὰ πίστις δι᾽ ἀγάπης ἐνεργουμένη</strong> (but faith working through love, G1754) — the present middle/passive participle; faith that is activated through love, or faith with love as the instrument of its activation. Love is not added to faith as a co-ground of salvation but describes the operative mode of genuine faith.</p>',
    "7": '<p><strong>ἐτρέχετε καλῶς</strong> (you were running well, imperfect) — the progressive imperfect describes the previous sustained good running; the athletic metaphor indicates forward progress now interrupted. <strong>τίς ὑμᾶς ἐνέκοψεν</strong> (who cut in on you, G1465) — the aorist of <em>enkoptō</em> (to cut into, interrupt): someone has cut across their lane. The unnamed agitator is the one who interrupted the race.</p>',
    "8": '<p><strong>ἡ πεισμονὴ οὐκ ἐκ τοῦ καλοῦντος ὑμᾶς</strong> (the persuasion is not from the one who calls you) — <em>peismonē</em> (G3988) is a hapax in the NT: persuasion, the quality of being persuaded. The persuasion the Galatians are following does not originate from the one who called them into Christ\'s grace (1:6).</p>',
    "9": '<p><strong>μικρὰ ζύμη ὅλον τὸ φύραμα ζυμοῖ</strong> (a little yeast works through the whole batch of dough, G2219) — the proverbial statement (also 1 Cor 5:6) about the pervading power of small quantities; the principle applies to the law-adding agitation: a small doctrinal corruption spreads through the whole community.</p>',
    "10": '<p><strong>ἐγὼ πέποιθα εἰς ὑμᾶς ἐν κυρίῳ</strong> (I am persuaded about you in the Lord) — the perfect <em>pepoitha</em> (I have been persuaded and remain persuaded): a standing confidence Paul maintains. <strong>ὁ δὲ ταράσσων ὑμᾶς βαστάσει τὸ κρίμα</strong> (but the one troubling you will bear the judgment, G941) — the singular <em>ho tarassōn</em> (the one troubling) individualizes the source of the trouble; <em>bastasei to krima</em> (will bear the judgment): the future tense points to eschatological accountability.</p>',
    "11": '<p><strong>τὸ σκάνδαλον τοῦ σταυροῦ</strong> (the stumbling block of the cross, G4625/G4716) — if Paul were preaching circumcision, the offense of the cross would be eliminated; the cross as <em>skandalon</em> is precisely the stumbling block to those seeking a righteousness they can claim credit for. The cross eliminates all human achievement-grounds; that is its scandal.</p>',
    "12": '<p><strong>ὄφελον καὶ ἀποκόψονται οἱ ἀναστατοῦντες ὑμᾶς</strong> (I wish those agitating you would go the whole way and castrate themselves) — the sarcastic irony: if circumcision is so important, why stop there? The rhetorical brutality serves the shock value of exposing the body-focused logic of the agitators by following it to its absurd conclusion. <em>Apokopto</em> (G609) means to cut off entirely.</p>',
    "13": '<p><strong>ὑμεῖς γὰρ ἐπ᾽ ἐλευθερίᾳ ἐκλήθητε, ἀδελφοί</strong> (for you were called to freedom, brothers, G1657) — the aorist passive marks the definitive past calling; freedom is the domain into which the call brought them. <strong>μόνον μὴ τὴν ἐλευθερίαν εἰς ἀφορμὴν τῇ σαρκί</strong> (only do not use freedom as an opportunity for the flesh, G4561 disp=4) — <em>aphormē</em> (G874, base of operations, opportunity): freedom must not become a base from which the flesh launches its campaigns.</p>',
    "14": '<p><strong>ὁ γὰρ πᾶς νόμος ἐν ἑνὶ λόγῳ πεπλήρωται</strong> (for the whole law is fulfilled in one word/commandment, G4137) — the perfect passive <em>peplērōtai</em>: a completed fulfillment that stands. The articular <em>ho pas nomos</em> (the whole law, with article) emphasizes comprehensiveness. <strong>ἀγαπήσεις τὸν πλησίον σου ὡς σεαυτόν</strong> (you shall love your neighbor as yourself, Lev 19:18) — the neighbor-love command from Leviticus as the law\'s single comprehensive form.</p>',
    "15": '<p><strong>εἰ δὲ ἀλλήλους δάκνετε καὶ κατεσθίετε</strong> (but if you bite and devour each other) — the animal-predation metaphor (<em>daknō</em> = bite; <em>katesthiō</em> = eat up/devour) describes the communal violence of competitive religious performance. <strong>βλέπετε μὴ ὑπ᾽ ἀλλήλων ἀναλωθῆτε</strong> (watch out lest you be consumed by each other) — the passive indicates mutual destruction through the very conflict that religious law-competition produces.</p>',
    "16": '<p><strong>πνεύματι περιπατεῖτε</strong> (walk by the Spirit, G4151 disp=3) — the present imperative: an ongoing, habitual practice. The dative <em>pneumati</em> is instrumental: walking with the Spirit as the means and standard. <strong>ἐπιθυμίαν σαρκὸς οὐ μὴ τελέσητε</strong> (you will absolutely not fulfill the desire of the flesh) — the double negative (<em>ou mē</em>) plus aorist subjunctive is the strongest possible negation: you will under no circumstances fulfill the flesh-desire.</p>',
    "17": '<p><strong>ἡ γὰρ σὰρξ ἐπιθυμεῖ κατὰ τοῦ πνεύματος, τὸ δὲ πνεῦμα κατὰ τῆς σαρκός</strong> (for the flesh desires against the Spirit, and the Spirit against the flesh, G4561 disp=4/G4151 disp=3) — the mutual opposition is cosmic and structural; both <em>sarx</em> and <em>pneuma</em> use the same verb <em>epithumeō</em> (desire toward, desire against). <strong>ταῦτα γὰρ ἀλλήλοις ἀντίκειται</strong> (for these are opposed to one another, G480) — the present tense describes an ongoing structural opposition, not occasional conflict.</p>',
    "18": '<p><strong>εἰ δὲ πνεύματι ἄγεσθε</strong> (but if you are led by the Spirit) — the present passive: being led is something happening to the person, not self-generated. <strong>οὐκ ἐστὲ ὑπὸ νόμον</strong> (you are not under the law) — the Spirit-led are not under the law because the Spirit is fulfilling the law\'s righteous requirement in them (cf. Rom 8:4); the law\'s guardianship function is superseded by the Spirit\'s direct leading.</p>',
    "19": '<p><strong>φανερὰ δέ ἐστιν τὰ ἔργα τῆς σαρκός</strong> (the works of the flesh are obvious, G4561 disp=4) — <em>phanera</em> (manifest, evident): no special spiritual insight is needed to identify them. <strong>ἔργα</strong> (works) — the plural underlines the productivity of the flesh-principle; it generates a variety of destructive outputs.</p>',
    "20": '<p><strong>εἰδωλολατρία, φαρμακεία</strong> (idolatry, sorcery/witchcraft) — <em>pharamakeia</em> (G5331) is the manipulation of spiritual powers through substances or rituals; both practices involve the replacement of God with alternative ultimate authorities. The social vices that follow (hatred, discord, jealousy, etc.) are equally "works of the flesh."</p>',
    "21": '<p><strong>βασιλείαν θεοῦ οὐ κληρονομήσουσιν</strong> (will not inherit the kingdom of God) — the future with absolute negative: those who practice (<em>prassontes</em>, present participle of habit) these things are excluding themselves from the inheritance that Paul has been arguing is available through Christ and the Spirit. The warning is to those who continue in such practices, not to those who struggle against them.</p>',
    "22": '<p><strong>ὁ δὲ καρπὸς τοῦ πνεύματος</strong> (but the fruit of the Spirit) — the singular <em>karpos</em> (fruit, G2590) contrasts with the plural <em>erga</em> (works) of v.19; the Spirit produces a unified, organic fruit rather than a catalog of separate achievements. The nine qualities listed are a single harvest, not a checklist. <strong>ἀγάπη χαρὰ εἰρήνη</strong> (love, joy, peace) — the first triad is relational; the second (patience, kindness, goodness) is dispositional; the third (faithfulness, gentleness, self-control) is volitional.</p>',
    "23": '<p><strong>κατὰ τῶν τοιούτων οὐκ ἔστιν νόμος</strong> (against such things there is no law) — the dry understatement: no law prohibits the fruit of the Spirit. The law was given for restraining transgression; where the Spirit\'s fruit flourishes, the law\'s restraining function has no application.</p>',
    "24": '<p><strong>οἱ δὲ τοῦ Χριστοῦ Ἰησοῦ τὴν σάρκα ἐσταύρωσαν</strong> (those who belong to Christ Jesus have crucified the flesh, G4717) — the possessive genitive <em>tou Christou</em> (belonging to Christ); the aorist <em>estaurōsan</em> marks a definitive past act, not an ongoing process: the crucifixion of the flesh is a completed event (cf. 2:20 "I have been crucified with Christ"). <strong>σὺν τοῖς παθήμασιν καὶ ταῖς ἐπιθυμίαις</strong> (with its passions and desires) — the flesh is crucified along with its characteristic outputs: the drives and desires that the vices of vv.19-21 express.</p>',
    "25": '<p><strong>εἰ ζῶμεν πνεύματι, πνεύματι καὶ στοιχῶμεν</strong> (if we live by the Spirit, let us also walk in step with the Spirit, G4748) — <em>stoicheō</em> (G4748) means to march in a row, keep in step with a line; the metaphor is military/processional rather than the general "walk" (<em>peripateō</em>) of v.16. The subjunctive <em>stoichōmen</em> is a hortatory call to maintain alignment with the Spirit whose life one already has.</p>',
    "26": '<p><strong>μὴ γινώμεθα κενόδοξοι</strong> (let us not become vainglorious, G2755) — <em>kenodoxos</em> = empty-glory-seeking; the present subjunctive <em>ginōmetha</em> is an ongoing prohibition: let us not become this. The three negative community-behaviors (empty boasting, provoking one another, envying) are the social pathologies that the flesh produces when the community forgets its shared Spirit-life.</p>'
  },
  "6": {
    "1": '<p><strong>ἐὰν καὶ προλημφθῇ ἄνθρωπός τινι παραπτώματι</strong> (if someone is caught/overtaken in some trespass, G4258) — <em>prolambhanō</em> may mean "caught in the act" or "overtaken, surprised." <strong>ὑμεῖς οἱ πνευματικοί</strong> (you the spiritual ones) — the adjective designates those who live by the Spirit (5:25); their responsibility for restoration is grounded in their Spirit-life. <strong>ἐν πνεύματι πρᾳΰτητος</strong> (in a spirit of gentleness) — the spirit/Spirit of gentleness: the same gentle quality named as a fruit of the Spirit (5:23).</p>',
    "2": '<p><strong>Ἀλλήλων τὰ βάρη βαστάζετε</strong> (bear one another\'s burdens, G941) — the present imperative: an ongoing practice. <strong>καὶ οὕτως ἀναπληρώσετε τὸν νόμον τοῦ Χριστοῦ</strong> (and in this way you will fulfill the law of Christ, G3551) — the future <em>anaplērōsete</em> (will fulfill, G378) has a different prefix from 5:14\'s <em>peplērōtai</em>; <em>ana-plēroō</em> means to fill up completely. The "law of Christ" (G3551 here in a positive sense) is not a new legal code but the governing principle of Christ\'s own self-giving (cf. 5:14: love your neighbor), described as "law" because it functions as the normative standard.</p>',
    "3": '<p><strong>εἰ γὰρ δοκεῖ τις εἶναί τι μηδὲν ὤν</strong> (for if anyone thinks they are something when they are nothing) — the self-deception here is the inflation of self-estimation that enables judgment of others (v.1\'s "you who are spiritual") while exempting oneself. The present participle <em>ōn</em> (being nothing) is the corrective reality check.</p>',
    "4": '<p><strong>τὸ δὲ ἑαυτοῦ ἔργον δοκιμαζέτω ἕκαστος</strong> (let each one examine/test their own work, G1381) — <em>dokimazō</em> is the test-and-approve verb; the examination is self-directed and specific to one\'s own <em>ergon</em> (work/action). <strong>εἰς ἑαυτὸν μόνον τὸ καύχημα ἕξει καὶ οὐκ εἰς τὸν ἕτερον</strong> (they will have ground for boasting in themselves alone and not in regard to another) — boasting grounded in comparative evaluation of others is eliminated; whatever ground for confidence exists is internal and self-referential.</p>',
    "5": '<p><strong>ἕκαστος γὰρ τὸ ἴδιον φορτίον βαστάσει</strong> (for each one will carry their own load) — the different word from v.2\'s <em>barē</em> (heavy burdens): <em>phortion</em> (G5413) is the pack or standard load, not an exceptional weight. There is no contradiction with v.2; each person has their own appropriate individual responsibility before God, while the community bears each other\'s excessive burdens.</p>',
    "6": '<p><strong>κοινωνείτω δὲ ὁ κατηχούμενος τὸν λόγον τῷ κατηχοῦντι ἐν πᾶσιν ἀγαθοῖς</strong> (let the one being instructed in the word share all good things with the one instructing, G2841) — the <em>koinōneō</em> verb indicates material sharing; the student-teacher relationship incurs a practical obligation of support. The <em>logos</em> (word) that is taught is the gospel.</p>',
    "7": '<p><strong>μὴ πλανᾶσθε· θεὸς οὐ μυκτηρίζεται</strong> (do not be deceived: God is not mocked, G3456) — <em>mykterizō</em> (G3456) literally means to turn up one\'s nose at someone in contempt; God cannot be treated with contemptuous disregard. <strong>ὃ γὰρ ἐὰν σπείρῃ ἄνθρωπος, τοῦτο καὶ θερίσει</strong> (for whatever a person sows, that is also what they will reap) — the agricultural axiom of cosmic accountability: the harvest corresponds to the seed.</p>',
    "8": '<p><strong>ὁ σπείρων εἰς τὴν σάρκα ἑαυτοῦ ἐκ τῆς σαρκὸς θερίσει φθοράν</strong> (the one sowing to their own flesh will reap corruption from the flesh, G4561 disp=4) — <em>sarx</em> here in its negative Pauline sense: the fallen human self-orientation. Sowing to the flesh is living to please the flesh-principle; the harvest is <em>phthora</em> (G5356, corruption/decay), the ultimate outcome of the Adamic existence. <strong>ὁ δὲ σπείρων εἰς τὸ πνεῦμα ἐκ τοῦ πνεύματος θερίσει ζωὴν αἰώνιον</strong> (but the one sowing to the Spirit will reap eternal life from the Spirit) — the harvest of Spirit-oriented living is <em>zōē aiōnios</em> (life of the age to come): the eschatological life that the Spirit is the firstfruits of.</p>',
    "9": '<p><strong>τὸ δὲ καλὸν ποιοῦντες μὴ ἐγκακῶμεν</strong> (in doing good let us not grow weary, G1573) — the present subjunctive hortatory: an ongoing encouragement to persevere. <strong>καιρῷ γὰρ ἰδίῳ θερίσομεν μὴ ἐκλυόμενοι</strong> (for in its own time we will reap if we do not give up) — <em>kairo idio</em> (in its own time): the harvest comes at the appointed time, not at the sower\'s preferred schedule; patience is essential to the agricultural metaphor.</p>',
    "10": '<p><strong>ὡς καιρὸν ἔχομεν</strong> (as we have opportunity, G2540) — <em>kairos</em> is the appointed, opportune moment; the phrase acknowledges that opportunity is given, not perpetually available. <strong>τοὺς οἰκείους τῆς πίστεως</strong> (those of the household of faith) — the community of believers is named as the primary, though not exclusive, recipients of practical good.</p>',
    "11": '<p><strong>ἴδετε πηλίκοις ὑμῖν γράμμασιν ἔγραψα τῇ ἐμῇ χειρί</strong> (see what large letters I write to you with my own hand) — Paul takes the pen from the scribe at this point (cf. 2 Thess 3:17; 1 Cor 16:21) to write a personal conclusion. The large letters may indicate poor eyesight (cf. 4:13-15), emphatic autograph, or both.</p>',
    "12": '<p><strong>ὅσοι θέλουσιν εὐπροσωπῆσαι ἐν σαρκί</strong> (those who want to make a good showing in the flesh, G2146) — <em>euprosōpeō</em> (G2146, a hapax) means to appear well, put on a good face; the motivation is appearance management. <strong>μόνον ἵνα τῷ σταυρῷ τοῦ Χριστοῦ μὴ διώκωνται</strong> (only so that they might not be persecuted for the cross of Christ) — the ultimate motivation for the agitators is avoiding the social cost of the cross\'s scandal (5:11).</p>',
    "13": '<p><strong>οὐδὲ γὰρ οἱ περιτεμνόμενοι αὐτοὶ νόμον φυλάσσουσιν</strong> (for not even those who are being circumcised keep the law themselves) — the present passive <em>peritemnomenoi</em> describes the ongoing circumcision-campaign; the exposure is ironic: the circumcision-advocates do not themselves keep the whole law they are requiring of others. <strong>ἀλλὰ θέλουσιν ὑμᾶς περιτέμνεσθαι, ἵνα ἐν τῇ ὑμετέρᾳ σαρκὶ καυχήσωνται</strong> (but they want you to be circumcised that they might boast in your flesh) — the flesh-boasting is the social credential of having brought Gentiles into circumcision.</p>',
    "14": '<p><strong>ἐμοὶ δὲ μὴ γένοιτο καυχᾶσθαι εἰ μὴ ἐν τῷ σταυρῷ τοῦ κυρίου ἡμῶν Ἰησοῦ Χριστοῦ</strong> (but far be it from me to boast except in the cross of our Lord Jesus Christ, G4716) — the optative <em>mē genoito</em> is the strongest possible wish-rejection. The cross as the exclusive ground of boasting inverts the agitators\' flesh-boasting. <strong>δι᾽ οὗ ἐμοὶ κόσμος ἐσταύρωται κἀγὼ κόσμῳ</strong> (through which the world has been crucified to me and I to the world) — both crucifixions are perfect passives: standing states; the world\'s claim on Paul and Paul\'s participation in the world\'s values have both been definitively ended by the cross.</p>',
    "15": '<p><strong>οὔτε γὰρ περιτομή τί ἐστιν οὔτε ἀκροβυστία ἀλλὰ καινὴ κτίσις</strong> (for neither circumcision nor uncircumcision is anything but a new creation, G2537) — the two ethnic-religious markers are declared null in the sphere of the gospel (cf. 5:6; 3:28). <em>Kainē ktisis</em> (new creation) is the comprehensive eschatological category that replaces both: the new-creation work of Christ in the believer, not a minor religious modification.</p>',
    "16": '<p><strong>τῷ κανόνι τούτῳ στοιχήσουσιν</strong> (as many as will march according to this rule, G2583) — <em>kanōn</em> (G2583) is the measuring standard or rule; the same <em>stoicheō</em> verb as 5:25 (walk in step with the Spirit). <strong>τὸν Ἰσραὴλ τοῦ θεοῦ</strong> (the Israel of God) — the phrase is debated: either all who follow the rule (Jew and Gentile = new covenant Israel) or specifically the Jewish believers who embrace the gospel. Given the letter\'s argument, it likely refers to all who are "in Christ" (3:29: "Abraham\'s seed"), which in Paul\'s usage constitutes the covenant community regardless of ethnicity.</p>',
    "17": '<p><strong>τὰ στίγματα τοῦ Ἰησοῦ ἐν τῷ σώματί μου βαστάζω</strong> (I bear on my body the marks of Jesus, G4742) — <em>stigmata</em> (G4742) are brand marks indicating ownership; slaves and devotees were branded. Paul\'s stigmata are the bodily scars from beatings and persecution suffered for the gospel of Jesus (2 Cor 11:24-25). The claim answers the agitators: he does not need the circumcision mark (flesh-based) because he already bears Jesus\'s marks (suffering-based).</p>',
    "18": '<p><strong>ἡ χάρις τοῦ κυρίου ἡμῶν Ἰησοῦ Χριστοῦ μετὰ τοῦ πνεύματος ὑμῶν, ἀδελφοί</strong> (the grace of our Lord Jesus Christ be with your spirit, brothers) — the closing benediction invokes grace from the specific person of Jesus Christ; the Spirit (<em>pneuma</em>) here is the human spirit of the Galatians, not the Holy Spirit. The blessing of grace upon the spirit rather than merely on the body or external circumstances matches the letter\'s entire argument: the new covenant is in the spirit and by grace, not in the flesh and by works.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'galatians')
    merge_comm(existing, GALATIANS)
    save_comm('mkt-original', 'galatians', existing)
    print('Galatians 4–6 mkt-original written.')

if __name__ == '__main__':
    main()
